security_scheme = HTTPBearer(
    scheme_name="Bearer Token",
    description="OAuth 2.0 Bearer Token",
    auto_error=True,
)


class OAuth2TokenValidator:
    """Dependency injection class for OAuth 2.0 token validation."""

    def __init__(self, required_scopes: Optional[list[str]] = None):
        self.required_scopes = required_scopes or []

    async def __call__(
        self,
        credentials: HTTPAuthorizationCredentials = Depends(security_scheme),
        redis_client: redis.Redis = Depends(get_redis),
    ) -> TokenData:
        token = credentials.credentials

        if not token:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Missing bearer token",
                headers={"WWW-Authenticate": "Bearer"},
            )

        try:
            token_key = f"{TOKEN_PREFIX}{token}"
            token_data_raw = await redis_client.get(token_key)
        except redis.RedisError as e:
            raise HTTPException(
                status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
                detail=f"Token store unavailable: {str(e)}",
            )

        if token_data_raw is None:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid or expired token",
                headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
            )

        try:
            token_dict = json.loads(token_data_raw)
            token_data = TokenData(**token_dict)
        except (json.JSONDecodeError, ValueError) as e:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail=f"Malformed token data: {str(e)}",
                headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
            )

        expires_at = datetime.fromisoformat(token_data.expires_at)
        if datetime.utcnow() > expires_at:
            await redis_client.delete(f"{TOKEN_PREFIX}{token}")
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Token has expired",
                headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
            )

        if self.required_scopes:
            missing_scopes = set(self.required_scopes) - set(token_data.scopes)
            if missing_scopes:
                raise HTTPException(
                    status_code=status.HTTP_403_FORBIDDEN,
                    detail=f"Insufficient scopes. Missing: {', '.join(missing_scopes)}",
                    headers={
                        "WWW-Authenticate": f'Bearer error="insufficient_scope", scope="{" ".join(self.required_scopes)}"'
                    },
                )

        return token_data


