@app.get("/health", response_model=HealthResponse, tags=["Health"])
async def health_check(redis_client: redis.Redis = Depends(get_redis)):
    redis_connected = False
    try:
        await redis_client.ping()
        redis_connected = True
    except Exception:
        pass

    return HealthResponse(
        status="healthy" if redis_connected else "degraded",
        redis_connected=redis_connected,
        timestamp=datetime.utcnow().isoformat(),
    )


@app.post("/tokens", response_model=TokenResponse, tags=["Token Management"])
async def create_token(
    request: TokenCreateRequest,
    redis_client: redis.Redis = Depends(get_redis),
):
    """Create a new OAuth 2.0 bearer token and store it in Redis.
    
    In production, this would be part of a full OAuth 2.0 authorization server.
    This simplified endpoint is for demonstration/testing purposes.
    """
    access_token = secrets.token_urlsafe(48)

    now = datetime.utcnow()
    expires_at = now + timedelta(seconds=TOKEN_EXPIRY_SECONDS)

    token_data = TokenData(
        user_id=request.user_id,
        scopes=request.scopes,
        client_id=request.client_id,
        expires_at=expires_at.isoformat(),
        created_at=now.isoformat(),
    )

    token_key = f"{TOKEN_PREFIX}{access_token}"

    try:
        await redis_client.setex(
            token_key,
            TOKEN_EXPIRY_SECONDS,
            token_data.model_dump_json(),
        )
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"Failed to store token: {str(e)}",
        )

    return TokenResponse(
        access_token=access_token,
        expires_in=TOKEN_EXPIRY_SECONDS,
        user_id=request.user_id,
        scopes=request.scopes,
    )


@app.delete("/tokens/revoke", tags=["Token Management"])
async def revoke_token(
    credentials: HTTPAuthorizationCredentials = Depends(security_scheme),
    redis_client: redis.Redis = Depends(get_redis),
):
    """Revoke a bearer token by removing it from Redis."""
    token = credentials.credentials
    token_key = f"{TOKEN_PREFIX}{token}"

    try:
        deleted = await redis_client.delete(token_key)
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"Failed to revoke token: {str(e)}",
        )

    if not deleted:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail="Token not found or already revoked",
        )

    return {"message": "Token revoked successfully"}


